import numpy as np

def encode_onehot(a):
    if len(a) == 0:
        return np.array([]).reshape((0, 0))

    # Get unique values in sorted order
    unique_vals = np.sort(np.unique(a))

    if len(unique_vals) == 0:
        return np.zeros((0, 0), dtype=bool)

    # Create one-hot encoding matrix
    num_unique = len(unique_vals)
    one_hot_matrix = np.zeros((num_unique, len(a), dtype=int), order='K')

    # Fill in the one-hot encoding
    for idx, val in enumerate(unique_vals):
        one_hot_matrix[idx, :] = a == val

    # Return the one-hot encoded 2D array
