import numpy as np

def remove_duplicates(arr):
    # Remove all zero values and adjacent duplicates for non-zero values
    result = []
    seen = set()
    for x in arr:
        if x == 0:
            continue
        if len(result) == 0 or result[-1] != x:
            result.append(x)
        seen.add(x)
    return np.array(result)
